import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  MapPin, 
  ShieldCheck, 
  Coins, 
  Edit3, 
  Plus, 
  Trash2, 
  Package, 
  ExternalLink 
} from 'lucide-react';

export default function Profile() {
  const [isEdit, setIsEdit] = useState(false);
  const [myListings, setMyListings] = useState([]);
  
  // Original Profile State
  const [profile, setProfile] = useState({
    name: "Arjun Das",
    location: "Kadavanthra, Kochi",
    tokens: 1450,
    skills: ["Web Design", "Gardening", "Plumbing"]
  });

  // Load newly created listings from LocalStorage
  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem('myListings')) || [];
    setMyListings(saved);
  }, []);

  const removeListing = (id) => {
    const updated = myListings.filter(item => item.id !== id);
    setMyListings(updated);
    localStorage.setItem('myListings', JSON.stringify(updated));
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }} 
      animate={{ opacity: 1 }} 
      className="p-10 max-w-5xl mx-auto space-y-8"
    >
      {/* 1. ORIGINAL HEADER CARD */}
      <div className="bg-white dark:bg-slate-900 rounded-[40px] p-10 shadow-sm border border-slate-50 dark:border-slate-800 flex flex-col md:flex-row items-center gap-10 transition-colors">
        <div className="w-32 h-32 bg-teal-50 dark:bg-teal-900/30 rounded-full flex items-center justify-center text-teal-600 text-4xl font-black border-4 border-white dark:border-slate-800 shadow-xl relative">
          {profile.name[0]}
          <div className="absolute -bottom-2 -right-2 bg-yellow-400 text-white p-2 rounded-xl shadow-lg">
            <Coins size={20} />
          </div>
        </div>

        <div className="flex-1 text-center md:text-left">
          <h1 className="text-4xl font-black text-slate-900 dark:text-white">{profile.name}</h1>
          <p className="text-slate-400 font-bold mt-2 flex items-center justify-center md:justify-start gap-2">
            <MapPin size={18} className="text-teal-600"/> {profile.location}
          </p>
          <div className="mt-4 inline-flex items-center gap-2 px-3 py-1 bg-teal-50 dark:bg-teal-900/30 text-teal-600 rounded-full text-[10px] font-black uppercase tracking-widest">
            <ShieldCheck size={14} /> Verified Member
          </div>
        </div>

        <div className="flex flex-col gap-3">
          <div className="bg-slate-900 dark:bg-teal-600 text-white px-8 py-4 rounded-[24px] text-center shadow-lg transition-colors">
            <p className="text-[10px] font-black uppercase tracking-widest opacity-70">Balance</p>
            <p className="text-2xl font-black">{profile.tokens} <span className="text-sm">WTK</span></p>
          </div>
          <button className="flex items-center justify-center gap-2 px-8 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 rounded-2xl font-bold hover:bg-slate-200 dark:hover:bg-slate-700 transition-all">
            <Edit3 size={18}/> Edit Profile
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* 2. ORIGINAL SKILLS SECTION */}
        <div className="lg:col-span-1 bg-white dark:bg-slate-900 rounded-[40px] p-10 border border-slate-50 dark:border-slate-800 shadow-sm h-fit">
          <h3 className="text-xl font-black text-slate-900 dark:text-white mb-6">Skill Tags</h3>
          <div className="flex flex-wrap gap-2">
            {profile.skills.map(skill => (
              <span key={skill} className="px-4 py-2 bg-teal-50 dark:bg-teal-900/20 text-teal-600 dark:text-teal-400 rounded-xl font-bold text-xs border border-teal-100 dark:border-teal-800">
                {skill}
              </span>
            ))}
          </div>
        </div>

        {/* 3. NEW DYNAMIC LISTINGS SECTION (Integrated into old structure) */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white dark:bg-slate-900 rounded-[40px] p-10 border border-slate-50 dark:border-slate-800 shadow-sm">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-slate-900 dark:text-white flex items-center gap-3">
                <Package className="text-teal-600" /> My Public Listings
              </h3>
              <span className="text-xs font-black text-slate-400 uppercase tracking-widest bg-slate-50 dark:bg-slate-800 px-3 py-1 rounded-lg">
                {myListings.length} Total
              </span>
            </div>

            <div className="space-y-4">
              {myListings.length > 0 ? (
                myListings.map(item => (
                  <motion.div 
                    layout
                    key={item.id} 
                    className="group flex items-center justify-between p-6 bg-slate-50 dark:bg-slate-800/50 rounded-3xl border border-transparent hover:border-teal-500/20 transition-all"
                  >
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white dark:bg-slate-900 rounded-2xl flex items-center justify-center text-teal-600 shadow-sm">
                        <ExternalLink size={20} />
                      </div>
                      <div>
                        <p className="font-bold text-slate-900 dark:text-white">{item.title}</p>
                        <p className="text-xs text-slate-400 font-bold uppercase tracking-tighter mt-1">{item.type} • {item.date}</p>
                      </div>
                    </div>
                    
                    <div className="flex items-center gap-6">
                      <span className="text-teal-600 font-black bg-white dark:bg-slate-900 px-4 py-2 rounded-xl shadow-sm">
                        {item.wtk} WTK
                      </span>
                      <button 
                        onClick={() => removeListing(item.id)}
                        className="p-2 text-slate-300 hover:text-red-500 transition-colors"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </motion.div>
                ))
              ) : (
                <div className="py-10 text-center border-2 border-dashed border-slate-100 dark:border-slate-800 rounded-3xl">
                  <p className="text-slate-400 font-medium">No listings found in your history.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </motion.div>
  );
}
